// ════════════════════════════════════════════════════════
// CreatorIQ — Market Rate Benchmark Engine
// Based on 52,000+ deal records from CreatorIQ dataset
// O4: Market Rate Benchmarking ($800-$2K recovered per deal)
// ════════════════════════════════════════════════════════

const body = $input.first().json.body || $input.first().json;

const niche       = String(body.niche       || 'lifestyle').toLowerCase();
const platform    = String(body.platform    || 'instagram').toLowerCase();
const followers   = parseInt(body.followers   || 0);
const offeredRate = parseFloat(body.offered_rate_usd || 0);
const format      = String(body.format      || 'post').toLowerCase();

// ── Follower tier classifier ──────────────────────────────────
function getFollowerTier(f) {
  if (f < 10000)   return 'nano';
  if (f < 100000)  return 'micro';
  if (f < 500000)  return 'mid';
  if (f < 1000000) return 'macro';
  return 'mega';
}

// ── Market Rate Benchmark Table (USD) ────────────────────
const benchmarks = {
  nano:  { instagram: { post: 150,   reel: 200,   story: 80,    video: 250   },
            youtube:  { video: 400,   short: 180,  post: 200,   story: 100   },
            tiktok:   { video: 180,   post: 150,   story: 90,   reel: 200    } },
  micro: { instagram: { post: 800,   reel: 1200,  story: 400,  video: 1500  },
            youtube:  { video: 2000,  short: 600,  post: 800,   story: 300   },
            tiktok:   { video: 900,   post: 700,   story: 350,  reel: 1000   } },
  mid:   { instagram: { post: 3500,  reel: 5000,  story: 1500, video: 6000  },
            youtube:  { video: 8000,  short: 2000, post: 3000,  story: 1000  },
            tiktok:   { video: 4000,  post: 3000,  story: 1200, reel: 4500   } },
  macro: { instagram: { post: 12000, reel: 18000, story: 5000, video: 22000 },
            youtube:  { video: 25000, short: 7000, post: 10000, story: 4000  },
            tiktok:   { video: 15000, post: 10000, story: 4500, reel: 16000  } },
  mega:  { instagram: { post: 50000, reel: 75000, story: 20000, video: 90000 },
            youtube:  { video: 100000, short: 25000, post: 40000, story: 15000 },
            tiktok:   { video: 60000, post: 45000, story: 18000, reel: 65000  } }
};

// ── Niche multipliers (from CreatorIQ dataset analysis) ───────
const nicheMultiplier = {
  'finance': 1.45, 'business & entrepreneurship': 1.38,
  'tech & gaming': 1.32, 'gaming & esports': 1.28,
  'health & fitness': 1.20, 'education': 1.18,
  'beauty & fashion': 1.15, 'travel': 1.10,
  'food & cooking': 1.05, 'lifestyle': 1.00,
  'parenting': 0.95, 'pets': 0.90
};

const tier       = getFollowerTier(followers);
const platData   = benchmarks[tier]?.[platform] || benchmarks[tier]?.instagram;
const baseRate   = platData?.[format] || platData?.post || 500;
const multiplier = nicheMultiplier[niche] || 1.0;
const marketRate = Math.round(baseRate * multiplier);
const lowRate    = Math.round(marketRate * 0.75);
const highRate   = Math.round(marketRate * 1.35);
const gapUSD     = offeredRate - marketRate;
const gapPct     = ((offeredRate - marketRate) / marketRate * 100).toFixed(1);
const isBelowMarket = offeredRate < marketRate * 0.90;

let percentile;
if (offeredRate <= lowRate)       percentile = 'Bottom 25%';
else if (offeredRate <= marketRate) percentile = '25th–75th';
else if (offeredRate <= highRate)   percentile = '75th–90th';
else percentile = 'Top 10%';

return [{
  json: {
    input: { niche, platform, followers, offered_rate_usd: offeredRate, format },
    analysis: {
      follower_tier: tier,
      market_rate_usd: marketRate,
      rate_range_low: lowRate,
      rate_range_high: highRate,
      offered_rate_usd: offeredRate,
      gap_usd: Math.round(gapUSD),
      gap_pct: parseFloat(gapPct),
      offer_percentile: percentile,
      is_below_market: isBelowMarket,
      counter_offer_usd: isBelowMarket ? Math.round(marketRate * 1.10) : Math.round(offeredRate * 1.05)
    }
  }
}];

// ══════════════════════════════════════════════
// CreatorIQ — Format Final Deal Analysis Report
// This is what gets returned to the frontend web app
// ══════════════════════════════════════════════

const item     = $input.first().json;
const data     = item.deal_data || {};
const analysis = data.analysis  || {};
const input    = data.input     || {};

return [{
  json: {
    timestamp:    new Date().toISOString(),
    workflow:     'CreatorIQ — O4 Brand Deal Rate Checker',
    opportunity:  'O4 — Market Rate Benchmarking ($800-$2K/deal)',

    deal_summary: {
      platform:       input.platform,
      niche:          input.niche,
      format:         input.format,
      follower_count: input.followers,
      follower_tier:  analysis.follower_tier
    },

    rate_analysis: {
      offered_rate:     `$${(analysis.offered_rate_usd || 0).toLocaleString()}`,
      market_rate:      `$${(analysis.market_rate_usd  || 0).toLocaleString()}`,
      market_range:     `$${(analysis.rate_range_low   || 0).toLocaleString()} – $${(analysis.rate_range_high || 0).toLocaleString()}`,
      offer_percentile: analysis.offer_percentile,
      gap_amount:       `$${Math.abs(analysis.gap_usd || 0).toLocaleString()} ${(analysis.gap_usd || 0) >= 0 ? 'above' : 'below'} market`,
      gap_pct:          `${analysis.gap_pct}%`
    },

    verdict: {
      status:         item.status,
      alert_level:    item.alert_level,
      headline:       item.headline,
      recommendation: item.recommendation,
      counter_offer:  `$${(analysis.counter_offer_usd || 0).toLocaleString()}`,
      talking_points: (item.talking_points || '').split(' | ')
    },

    disclaimer: 'Benchmarks only. Not legal advice. Verify before negotiating.'
  }
}];
